+fn addrinfo_from_text_address(
+    text_addr: &[u8],
+    family: i32,
+    socktype: i32,
+    protocol: i32,
+) -> Option<AddrInfo> {
+    let text = core::str::from_utf8(text_addr).ok()?;
+    if (family == AF_UNSPEC || family == AF_INET)
+        && let Ok(v4) = text.parse::<Ipv4Addr>()
+    {
